mapper.sql:
e.tenant_id = #{tenantId}
AND e.deleted_flag = 0
AND e.account_id = #{query.accountId}
AND e.direction = #{query.direction}
AND e.status = #{query.status}
AND e.source_type = #{query.sourceType}
AND e.source_id = #{query.sourceId}
AND e.project_id = #{query.projectId}
AND e.contract_id = #{query.contractId}
AND e.business_date >= #{query.businessDateStart}
AND e.business_date <= #{query.businessDateEnd}

    AND EXISTS (
        SELECT 1 FROM sys_file f
        WHERE f.tenant_id = e.tenant_id
          AND f.business_type = 'CASH_JOURNAL'
          AND f.business_id = e.id
          AND f.deleted_flag = 0
    )


    AND NOT EXISTS (
        SELECT 1 FROM sys_file f
        WHERE f.tenant_id = e.tenant_id
          AND f.business_type = 'CASH_JOURNAL'
          AND f.business_id = e.id
          AND f.deleted_flag = 0
    )


    AND (e.entry_no LIKE CONCAT('%', #{query.keyword}, '%')
      OR e.summary LIKE CONCAT('%', #{query.keyword}, '%')
      OR e.counterparty_name LIKE CONCAT('%', #{query.keyword}, '%'))
